#include <bits/stdc++.h>
using namespace std;

const int N=110,M=1e4+10;

int n,m,a[M],d[N][N],f[N][N];
long long ans;

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++){
            scanf("%d",&d[i][j]);
            f[i][j]=d[i][j];
        }
    for(int k=1;k<=n;k++)
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                f[i][j]=min(f[i][j],f[i][k]+f[k][j]);
    for(int i=2;i<=m;i++)
        ans+=f[a[i-1]][a[i]];
    printf("%lld",ans);
    return 0;
}
